CREATE TABLE "video"."videos" ("id" uuid NOT NULL DEFAULT gen_random_uuid(), "created_at" timestamptz NOT NULL DEFAULT now(), "original_filename" Text NOT NULL, "mime" text NOT NULL, "probe_result" jsonb, "bytesize" bigint NOT NULL, "creator_id" uuid NOT NULL, "project_id" UUID NOT NULL, PRIMARY KEY ("id") , FOREIGN KEY ("project_id") REFERENCES "video"."projects"("id") ON UPDATE restrict ON DELETE restrict, FOREIGN KEY ("creator_id") REFERENCES "identity"."users"("id") ON UPDATE restrict ON DELETE restrict);COMMENT ON TABLE "video"."videos" IS E'Bulk storage for assets';
CREATE EXTENSION IF NOT EXISTS pgcrypto;
